          "id": "contact",
          "label": "Contact",
          "kind": "emailModules",
          "modules": [
            "contact"
          ],
          "libraryHtml": "<section class=\"test-section\" id=\"email-contact\">\n  <div class=\"test-module-row\">\n    <div class=\"module-copy\" data-module=\"contact\">\n      <button class=\"module-copy__button\" type=\"button\" aria-label=\"contact kopieren\" title=\"contact kopieren\">\n        <span class=\"module-copy__name\">contact</span>\n        <svg class=\"module-copy__icon module-copy__icon--default\" viewBox=\"0 0 24 24\"><rect x=\"9\" y=\"9\" width=\"13\" height=\"13\" rx=\"2\" ry=\"2\"></rect><path d=\"M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1\"></path></svg>\n        <span class=\"module-copy__icon--success\" aria-hidden=\"true\"></span>\n      </button>\n    </div>\n    <div class=\"test-module-frame\">\n      <div class=\"test-email-preview\" data-email-preview-module=\"contact\">\n        <!-- MODULE: contact | SNIPPET: emb_contact -->\n        <section class=\"module theme-white\" data-module=\"contact\" data-snippet=\"emb_contact\">\n          <div class=\"module__inner\">\n            <div class=\"contact-card\">\n              <span class=\"is-hidden\" data-export-field=\"emb_contact_show_image\" data-export-role=\"technical-flag\">false</span>\n              <div class=\"contact-head\">\n                <div class=\"contact-media\">\n                  <div\n                    class=\"preview-image-placeholder preview-image-placeholder--contact-avatar\"\n                    data-image-field=\"emb_contact_image_url\"\n                    data-image-alt-field=\"emb_contact_image_alt\"\n                  >\n                    <div class=\"preview-image-placeholder__text\">\n                      <p class=\"preview-image-placeholder__meta\">104 x 104 px</p>\n                    </div>\n                  </div>\n                </div>\n                <div class=\"contact-head__copy\">\n                  <h2 class=\"module__title module__title--medium\" data-export-field=\"emb_contact_headline\" data-export-role=\"headline\">Wir sind für Sie da</h2>\n                  <div class=\"module__teaser-richtext\" data-export-field=\"emb_contact_body_intro\" data-export-role=\"richtext\">\n                    <p class=\"module__body\" data-export-role=\"body-paragraph\" data-export-index=\"1\">Sie möchten Ihre Mail oder Ihren Builder-Stand gemeinsam schärfen? Unser Team unterstützt Sie gern beim nächsten Schritt.</p>\n                    <ul class=\"module__list--teaser\">\n                      <li data-export-item=\"contact-intro-list-item\" data-export-index=\"1\">Wir prüfen Inhalte, Struktur und Builder-Stand gemeinsam</li>\n                      <li data-export-item=\"contact-intro-list-item\" data-export-index=\"2\">Rückfragen und Abstimmungen lassen sich direkt im Team klären</li>\n                    </ul>\n                    <p class=\"module__body\" data-export-role=\"body-paragraph\" data-export-index=\"2\">So kommen Sie schneller zu einer sauberen und versandbereiten Mail.</p>\n                  </div>\n                </div>\n              </div>\n              <div class=\"contact-copy\">\n                <p class=\"contact-phone\" data-export-field=\"emb_contact_phone\" data-export-role=\"phone\">030 12345678</p>\n                <p class=\"module__body\" data-export-field=\"emb_contact_phone_hours\" data-export-role=\"phone-hours\">Montag bis Freitag, 9 bis 18 Uhr</p>\n                <p class=\"module__body\" data-export-field=\"emb_contact_email_intro\" data-export-role=\"email-intro\">Oder schreiben Sie uns direkt per E-Mail:</p>\n                <p class=\"module__body\"><a class=\"contact-link\" href=\"mailto:beratung@immobilienscout24.de\" data-token-attr-href=\"contact.email_url\" data-token-text=\"contact.email_address\" data-export-field=\"emb_contact_email_address\" data-export-url-field=\"emb_contact_email_url\" data-export-role=\"email-link\">beratung@immobilienscout24.de</a></p>\n                <p class=\"contact-signoff\"><span data-export-field=\"emb_contact_closing_line_1\" data-export-role=\"closing-line\" data-export-index=\"1\">Viele Grüße</span><br><span data-export-field=\"emb_contact_closing_line_2\" data-export-role=\"closing-line\" data-export-index=\"2\">Ihr Builder-Team</span></p>\n              </div>\n            </div>\n          </div>\n        </section>\n      </div>\n    </div>\n  </div>\n</section>"
